// Import of required libraries
import { test, newSkyrampPlaywrightPage, expect } from '@skyramp/skyramp';

const pageTimeout = 15000;

test('testUi', async ({ page }) => {
    test.setTimeout(67000);

    // set default timeout for all locator/page actions in this test
    page.setDefaultTimeout(pageTimeout);
    // Wrap playwright page with Skyramp page
    page = newSkyrampPlaywrightPage(page);

    const errors: string[] = [];
    page.on('pageerror', err => errors.push(err.message));

    await page.goto("http://localhost:8055/admin/login");
    await page.getByRole("textbox", { name: "Email" }).fill("admin@example.com");
    await page.getByRole("textbox", { name: "Password" }).fill("admin");
    await page.getByRole("button", { name: "Sign In" }).click();
    await expect(page).toHaveURL(/\/admin\/content/);
    await page.getByRole("button", { name: "Remind Later" }).click();
    await page.getByRole("button", { name: "left_panel_close" }).click();
    await expect(page.getByRole('button', { name: 'left_panel_open' })).toBeVisible();
    await expect(page.getByRole('navigation', { name: 'Module Navigation' })).toHaveAttribute('data-panel-size', '0');
    await page.getByRole("button", { name: "left_panel_open" }).click();
    await expect(page.getByRole('button', { name: 'left_panel_open' })).not.toBeVisible();
    await expect(page.getByRole('navigation', { name: 'Module Navigation' })).toHaveAttribute('data-panel-size', /^[1-9]\d*$/);
    expect(errors).toHaveLength(0);
});
